#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <omp.h>

#include "../common.h"

static double translated_time_diff_ms(const struct timeval *end, const struct timeval *start) {
    return (double)(end->tv_sec - start->tv_sec) * 1000.0 +
           (double)(end->tv_usec - start->tv_usec) / 1000.0;
}

void
kernel_gpu_opencl_wrapper( record *records,
                           long records_mem,
                           knode *knodes,
                           long knodes_elem,
                           long knodes_mem,

                           int order,
                           long maxheight,
                           int count,

                           long *currKnode,
                           long *offset,
                           int *keys,
                           record *ans)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_close_start, tv_close_end;
    double init_time = 0.0, mem_alloc_time = 0.0, h2d_time = 0.0;
    double kernel_time = 0.0, d2h_time = 0.0, close_time = 0.0, total_time = 0.0;
    gettimeofday(&tv_total_start, NULL);
#endif

    printf("Platform: OpenMP\n");
    printf("Device num: 1\n");
    printf("Creating CPU Context\n");
    printf("Device: OpenMP Host\n");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = translated_time_diff_ms(&tv_init_end, &tv_total_start);
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    record *recordsD = (record *)malloc((size_t)records_mem);
    knode *knodesD = (knode *)malloc((size_t)knodes_mem);
    long *currKnodeD = (long *)malloc((size_t)count * sizeof(long));
    long *offsetD = (long *)malloc((size_t)count * sizeof(long));
    int *keysD = (int *)malloc((size_t)count * sizeof(int));
    record *ansD = (record *)malloc((size_t)count * sizeof(record));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = translated_time_diff_ms(&tv_mem_alloc_end, &tv_mem_alloc_start);
    gettimeofday(&tv_h2d_start, NULL);
#endif

    memcpy(recordsD, records, (size_t)records_mem);
    memcpy(knodesD, knodes, (size_t)knodes_mem);
    memcpy(currKnodeD, currKnode, (size_t)count * sizeof(long));
    memcpy(offsetD, offset, (size_t)count * sizeof(long));
    memcpy(keysD, keys, (size_t)count * sizeof(int));
    memcpy(ansD, ans, (size_t)count * sizeof(record));

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    h2d_time = translated_time_diff_ms(&tv_h2d_end, &tv_h2d_start);
#endif

    {
        size_t local_work_size = (size_t)(order < 1024 ? order : 1024);
        size_t global_work_size = (size_t)count * local_work_size;

        printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
               (int)(global_work_size / local_work_size), (int)local_work_size);

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

#pragma omp parallel for schedule(static)
        for (int bid = 0; bid < count; bid++) {
            long curr = currKnodeD[bid];
            long off = offsetD[bid];

            for (long level = 0; level < maxheight; level++) {
                for (int thid = 0; thid < (int)local_work_size; thid++) {
                    if ((knodesD[curr].keys[thid] <= keysD[bid]) &&
                        (knodesD[curr].keys[thid + 1] > keysD[bid])) {
                        if (knodesD[off].indices[thid] < knodes_elem) {
                            off = knodesD[off].indices[thid];
                        }
                    }
                }
                curr = off;
            }

            for (int thid = 0; thid < (int)local_work_size; thid++) {
                if (knodesD[curr].keys[thid] == keysD[bid]) {
                    ansD[bid].value = recordsD[knodesD[curr].indices[thid]].value;
                }
            }

            currKnodeD[bid] = curr;
            offsetD[bid] = off;
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        kernel_time = translated_time_diff_ms(&tv_kernel_end, &tv_kernel_start);
        gettimeofday(&tv_d2h_start, NULL);
#endif
    }

    memcpy(ans, ansD, (size_t)count * sizeof(record));

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    d2h_time = translated_time_diff_ms(&tv_d2h_end, &tv_d2h_start);
    gettimeofday(&tv_close_start, NULL);
#endif

    free(recordsD);
    free(knodesD);
    free(currKnodeD);
    free(offsetD);
    free(keysD);
    free(ansD);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = translated_time_diff_ms(&tv_close_end, &tv_close_start);
    tv_total_end = tv_close_end;
    total_time = translated_time_diff_ms(&tv_total_end, &tv_total_start);

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", (float)init_time);
    printf("MemAlloc: %f\n", (float)mem_alloc_time);
    printf("HtoD: %f\n", (float)h2d_time);
    printf("Exec: %f\n", (float)kernel_time);
    printf("DtoH: %f\n", (float)d2h_time);
    printf("Close: %f\n", (float)close_time);
    printf("Total: %f\n", (float)total_time);
#endif
}

